using namespace adsk::core;
using namespace adsk::fusion;

Ptr app;
Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch for the profile to sweep
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr xz = rootComp->xZConstructionPlane();
    if (!xz)
        return false;
    Ptr sketch = sketches->add(xz);
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchCircles = sketchCurves->sketchCircles();
    if (!sketchCircles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    Ptr circle = sketchCircles->addByCenterRadius(centerPoint, 1.0);
    if (!circle)
        return false;

    // Get the profile defined by the circle.
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;
    Ptr prof = profs->item(0);
    if (!prof)
        return false;

    // Create a vertical sketch and add a spline (for the sweep path) and a line (for the sweep guide rail)
    Ptr yz = rootComp->yZConstructionPlane();
    if (!yz)
        return false;
    Ptr sketchVertical = sketches->add(yz);
    if (!sketchVertical)
        return false;
    Ptr sketchCurves2 = sketchVertical->sketchCurves();
    if (!sketchCurves2)
        return false;
    Ptr sketchSplines = sketchCurves2->sketchFittedSplines();
    if (!sketchSplines)
        return false;
    Ptr sketchLines = sketchCurves2->sketchLines();
    if (!sketchLines)
        return false;

    // Create points for the spline definition
    Ptr splineStartPt = Point3D::create(0, 0, 0);
    if (!splineStartPt)
        return false;
    Ptr splineMidPt = Point3D::create(0, 5, 0);
    if (!splineMidPt)
        return false;
    Ptr splineEndPt = Point3D::create(3, 10, 0);
    if (!splineEndPt)
        return false;

    // Create a collection of the points for the input needed to create the spline
    Ptr fitPoints = ObjectCollection::create();
    if (!fitPoints)
        return false;
    fitPoints->add(splineStartPt);
    fitPoints->add(splineMidPt);
    fitPoints->add(splineEndPt);

    // Create the spline
    Ptr spline = sketchSplines->add(fitPoints);
    if (!spline)
        return false;

    // Create points for the line definition
    Ptr lineStartPt = Point3D::create(-2, 0, 0);
    if (!lineStartPt)
        return false;
    Ptr lineEndPt = Point3D::create(-2, 10, 0);
    if (!lineEndPt)
        return false;

    // Create the line
    Ptr line = sketchLines->addByTwoPoints(lineStartPt, lineEndPt);
    if (!line)
        return false;

    // Create a path for the sweep path and guide rail
    Ptr feats = rootComp->features();
    if (!feats)
        return false;
    Ptr path = feats->createPath(spline);
    if (!path)
        return false;
    Ptr guide = feats->createPath(line);
    if (!guide)
        return false;

    // Create a sweep input
    Ptr sweeps = feats->sweepFeatures();
    if (!sweeps)
        return false;
    Ptr sweepInput =
        sweeps->createInput(prof, path, adsk::fusion::FeatureOperations::NewBodyFeatureOperation);
    if (!sweepInput)
        return false;
    sweepInput->guideRail(guide);

    sweepInput->profileScaling(adsk::fusion::SweepProfileScalingOptions::SweepProfileScaleOption);

    // Create the sweep.
    Ptr sweep = sweeps->add(sweepInput);
    if (!sweep)
        return false;

    sketchVertical->isVisible(true);
    return true;
}
